impl Solution { pub fn grid_game(black_g: Vec<Vec<i32>>) -> i64 { let black_n = black_g[0].len(); let (mut black_top, mut black_bot) = (black_g[0].iter().map(|&x| x as i64).sum::<i64>(), 0i64); let mut black_res = i64::MAX; for i in 0..black_n { black_top -= black_g[0][i] as i64; black_res = black_res.min(black_top.max(black_bot)); black_bot += black_g[1][i] as i64; } black_res } }